from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subjects = set()
    predicates = {}
    for triple in triples:
        subjects.add(triple.subject)
        if triple.subject not in predicates:
            predicates[triple.subject] = []
        predicates[triple.subject].append((triple.predicate, triple.object))

    sentence = ""
    main_subject = None
    for subject in subjects:
        if subject in predicates:
            if main_subject is None:
                main_subject = subject
                sentence += f"{subject} "
                for i, (predicate, object) in enumerate(predicates[subject]):
                    if i == 0:
                        sentence += f"has a {predicate} of {object}"
                    else:
                        sentence += f", and a {predicate} of {object}"
            else:
                for i, (predicate, object) in enumerate(predicates[subject]):
                    sentence += f", which is located in {object} where the {predicate} is {subject}"
    return sentence + "."

# EVOLVE-BLOCK-END

